const serviceRoutes = Object.fromEntries(services.map(service => [service.slug, `/services/${service.slug}`])) as Record<string, string>
const allowedStandaloneRoutes = new Set(['/septic-assessment-form', '/terms-of-service', '/privacy-compliance', '/blog/winter-reclamation-story', '/blog'])

declare global {
  interface Window {
    OzzysChatNavigation?: {
      goToService: (serviceSlug: string) => string
      startQuote: (serviceSlug?: string) => string
      startSepticAssessment: () => string
      scrollToSection: (sectionId: string) => string
      navigateToAllowedPath: (path: string) => string
    }
  }
}

function normalizeInternalPath(path: string) {
  if (!path) return ''
  try {
    const url = new URL(path, window.location.origin)
    if (url.origin !== window.location.origin) return ''
    return `${url.pathname}${url.search}${url.hash}`
  } catch {
    return ''
  }
}

function chatNavigateTo(path: string) {
  const normalized = normalizeInternalPath(path)
  if (!normalized) return "Navigation blocked: only internal Ozzy's Excavation pages are allowed."
  const [pathnameWithSearch] = normalized.split('#')
  const [pathname] = pathnameWithSearch.split('?')
  const isAllowed = pathname === '/' || allowedStandaloneRoutes.has(pathname) || Object.values(serviceRoutes).includes(pathname)
  if (!isAllowed) return 'Navigation blocked: page is not on the approved navigation list.'
  window.history.pushState({}, '', normalized)
  window.dispatchEvent(new Event('ozzys:navigation'))
  return `Opened ${normalized}.`
}

function setupChatNavigationHelpers() {
  window.OzzysChatNavigation = {
    goToService: (serviceSlug: string) => {
      const route = serviceRoutes[serviceSlug]
      if (!route) return 'Unknown service. Navigation blocked.'
      return chatNavigateTo(route)
    },
    startQuote: (serviceSlug = '') => {
      if (serviceSlug === 'septic-services') return chatNavigateTo('/septic-assessment-form')
      const query = serviceSlug && serviceRoutes[serviceSlug] ? `?service=${encodeURIComponent(serviceSlug)}` : ''
      return chatNavigateTo(`/${query}#quote`)
    },
    startSepticAssessment: () => chatNavigateTo('/septic-assessment-form'),
    scrollToSection: (sectionId: string) => {
      const allowedSections = new Set(['home', 'about', 'services', 'quote', 'coverage', 'septic-assessment-form', 'septic-assessment-top'])
      if (!allowedSections.has(sectionId)) return 'Unknown section. Navigation blocked.'
      scrollTo(sectionId)
      return `Moved to ${sectionId}.`
    },
    navigateToAllowedPath: chatNavigateTo,
  }
}

function scrollTo(id: string) {
  const el = document.getElementById(id)
  if (!el) {
    if (window.location.pathname !== '/') window.location.href = `/#${id}`
    return
  }
  const navHeight = document.querySelector('header')?.getBoundingClientRect().height ?? 0
  const top = el.getBoundingClientRect().top + window.scrollY - navHeight
  window.scrollTo({ top, behavior: 'smooth' })
}

function setMeta(name: string, content: string, property = false) {
  const selector = property ? `meta[property="${name}"]` : `meta[name="${name}"]`
  let tag = document.head.querySelector<HTMLMetaElement>(selector)
  if (!tag) {
    tag = document.createElement('meta')
    tag.setAttribute(property ? 'property' : 'name', name)
    document.head.appendChild(tag)
  }
  tag.content = content
}

function setCanonical(url: string) {
  let tag = document.head.querySelector<HTMLLinkElement>('link[rel="canonical"]')
  if (!tag) {
    tag = document.createElement('link')
    tag.rel = 'canonical'
    document.head.appendChild(tag)
  }
  tag.href = url
}

function PageMetadata({ title, description, keywords, url }: { title: string; description: string; keywords?: string[]; url: string }) {
  useEffect(() => {
    document.title = title
    setMeta('description', description)
    if (keywords?.length) setMeta('keywords', keywords.join(', '))
    setMeta('og:title', title, true)
    setMeta('og:description', description, true)
    setMeta('og:url', url, true)
    setCanonical(url)
  }, [title, description, keywords, url])
  return null
}

